changeSet.sql:
ALTER TABLE auth_event DROP CONSTRAINT ck_auth_event_event_type;
ALTER TABLE auth_event ADD CONSTRAINT ck_auth_event_event_type CHECK (event_type IN (
    'LOGIN', 'LOGIN_FAILED', 'LOGOUT', 'TOKEN_REFRESH', 'JWT_REVOKED',
    'IDENTITY_LINKED', 'IDENTITY_UNLINKED',
    'IMPERSONATION_BEGIN', 'IMPERSONATION_END',
    'ACCOUNT_DELETED',
    'EXPORT_REQUESTED', 'APP_ROLE_CHANGED',
    'RESEARCH_CONSENT_REVOKED'
));

rollback.sql:
