changeSet.sql:
ALTER TABLE observation DROP CONSTRAINT IF EXISTS chk_observation_target_type;
ALTER TABLE observation
ADD CONSTRAINT chk_observation_target_type
CHECK (artifact_type IN ('PULL_REQUEST', 'ISSUE', 'CONVERSATION_THREAD'));

